def simulate_db_query(table, item_id=None):
    """Simulates fetching data from a database."""
    print(f"--- Simulating DB query for {table}{f' ID={item_id}' if item_id else ''} ---")
    if item_id:
        return _mock_database.get(table, {}).get(item_id)
    return list(_mock_database.get(table, {}).values())

# --- Caching Decorator ---
def cached(key_prefix, ttl=DEFAULT_TTL_SECONDS):
    """
    Decorator to cache the result of a function.
    Assumes the decorated function returns a JSON-serializable object.
    """
    def decorator(func):
        def wrapper(*args, **kwargs):
            cache_key = f"{key_prefix}:{func.__name__}:{request.full_path}" # Use full path for API responses
            
            # Try to get from cache
            cached_result = cache.get(cache_key)
            if cached_result:
                print(f"--- Cache HIT for key: {cache_key} ---")
                return jsonify(eval(cached_result.decode('utf-8'))) # pymemcache stores bytes, eval to get back dict/list
            
            print(f"--- Cache MISS for key: {cache_key} ---")
            # If not in cache, call the original function
            result = func(*args, **kwargs)
            
            # Store in cache
            if result is not None:
                # Store as string representation of the JSON response body
                cache.set(cache_key, str(result.json), expire=ttl)
            
            return result
        return wrapper
    return decorator

